    guard diagStatsTask == nil else { return }
    Loggers.app.log(.info, "[CPU-DIAG] starting menu-bar refresh diagnostics (flush every 2 s)")
    diagStatsTask = Task { @MainActor [weak self] in
        while !Task.isCancelled {
            try? await Task.sleep(nanoseconds: 2 * 1_000_000_000)
            guard let self else { return }
            let refresh = self.diagRefreshCount
            let onChange = self.diagOnChangeCount
            let identical = self.diagIdenticalRepublishCount
            let appearance = self.diagAppearanceFireCount
            self.diagRefreshCount = 0
            self.diagOnChangeCount = 0
            self.diagIdenticalRepublishCount = 0
            self.diagAppearanceFireCount = 0
            let shortCircuitRefresh = self.diagShortCircuitedRefreshes
            let shortCircuitAppearance = self.diagShortCircuitedAppearance
            self.diagShortCircuitedRefreshes = 0
            self.diagShortCircuitedAppearance = 0
            Loggers.app.log(
