import Foundation
import Testing
@testable import AIUsagesTrackersLib

@MainActor
@Suite("MenuBarRefreshController — dedup")
struct MenuBarRefreshControllerTests {
    private func makeKey(
        text: String = "x",
        separator: String = " | ",
        isDark: Bool = true,
        isUnconfigured: Bool = false,
        segments: [MenuBarSegment] = [
            MenuBarSegment(text: "Claude", tier: nil, showDot: true, vendorIcon: nil)
        ]
    ) -> MenuBarRenderKey {
        MenuBarRenderKey(
            segments: segments,
            text: text,
            separator: separator,
            isDark: isDark,
            isUnconfigured: isUnconfigured
        )
    }

    @Test("First refresh always runs onRender exactly once")
    func firstRefreshAlwaysFires() {
        var calls: [MenuBarRenderKey] = []
        let sut = MenuBarRefreshController { calls.append($0) }
        let key = makeKey()

        sut.refresh(key: key)

        #expect(calls == [key])
        #expect(sut.renderCount == 1)
    }

    @Test("1000 identical refreshes only render once — the dedup that broke the feedback loop")
    func identicalRefreshesAreDeduped() {
        var calls = 0
        let sut = MenuBarRefreshController { _ in calls += 1 }
        let key = makeKey()

        for _ in 0..<1000 {
            sut.refresh(key: key)
        }

        #expect(calls == 1)
        #expect(sut.renderCount == 1)
    }

    @Test(
        "Each field of MenuBarRenderKey individually invalidates the cache",
        arguments: [
            ("text", { (k: MenuBarRenderKey) in
                MenuBarRenderKey(segments: k.segments, text: "other", separator: k.separator, isDark: k.isDark, isUnconfigured: k.isUnconfigured)
            }),
            ("separator", { (k: MenuBarRenderKey) in
                MenuBarRenderKey(segments: k.segments, text: k.text, separator: " · ", isDark: k.isDark, isUnconfigured: k.isUnconfigured)
            }),
            ("isDark", { (k: MenuBarRenderKey) in
                MenuBarRenderKey(segments: k.segments, text: k.text, separator: k.separator, isDark: !k.isDark, isUnconfigured: k.isUnconfigured)
            }),
            ("isUnconfigured", { (k: MenuBarRenderKey) in
                MenuBarRenderKey(segments: k.segments, text: k.text, separator: k.separator, isDark: k.isDark, isUnconfigured: !k.isUnconfigured)
            }),
            ("segments", { (k: MenuBarRenderKey) in
                MenuBarRenderKey(
                    segments: [MenuBarSegment(text: "Codex", tier: nil, showDot: false, vendorIcon: nil)],
                    text: k.text, separator: k.separator, isDark: k.isDark, isUnconfigured: k.isUnconfigured
                )
            })
        ]
    )
    func eachFieldInvalidatesDedup(arg: (String, (MenuBarRenderKey) -> MenuBarRenderKey)) {
        var calls = 0
        let sut = MenuBarRefreshController { _ in calls += 1 }
        let original = makeKey()
        let mutated = arg.1(original)

        sut.refresh(key: original)
        sut.refresh(key: mutated)
        sut.refresh(key: mutated)

        #expect(calls == 2, "field=\(arg.0) — expected exactly 2 renders, got \(calls)")
    }

    @Test("Appearance KVO filter ignores fires that don't move dark/aqua")
    func appearanceFilterIgnoresUnchangedFlag() {
        let sut = MenuBarRefreshController { _ in }
        sut.refresh(key: makeKey(isDark: true))

        // 100 KVO fires reporting the same isDark = true — none should warrant a refresh.
        for _ in 0..<100 {
            #expect(sut.shouldHandleAppearanceChange(isDark: true) == false)
        }
    }

    @Test("Appearance KVO filter authorises refresh on actual dark/aqua flip")
    func appearanceFilterAuthorisesOnFlip() {
        let sut = MenuBarRefreshController { _ in }
        sut.refresh(key: makeKey(isDark: true))

        #expect(sut.shouldHandleAppearanceChange(isDark: false) == true)
        // After a flip is consumed, further fires at the same value are filtered again.
        #expect(sut.shouldHandleAppearanceChange(isDark: false) == false)
        #expect(sut.shouldHandleAppearanceChange(isDark: true) == true)
    }
}

