        let url = URL(fileURLWithPath: NSTemporaryDirectory())
            .appendingPathComponent("aiut-smoke-\(UUID().uuidString)")
        try FileManager.default.createDirectory(at: url, withIntermediateDirectories: true)
        return url
    }
}

